// Solution
function filterQuery(query, excludedFields) {
  const projection = {};
  const keys = Object.keys(query);
  for (const key of keys) {
    if (typeof query[key] === 'object' || Array.isArray(query[key])) {
      continue;
    }
    projection[key] = query[key];
  }
  return projection;
}

